def generate_knowledge_production_report(
    quarter: str,
    prompt_library: dict,
    showcase_data: dict,
    office_hours_data: dict,
    channel_data: dict,
) -> str:
    """Generate a knowledge production report for the quarterly CoP review."""
    prompt = f"""Write a knowledge production report for a Claude CoP quarterly review.

Quarter: {quarter}

Prompt library:
- Total entries: {prompt_library.get("total_entries", 0)}
- New this quarter: {prompt_library.get("new_this_quarter", 0)}
- Archived (outdated): {prompt_library.get("archived", 0)}
- Monthly unique views (mean): {prompt_library.get("monthly_views_mean", 0)}
- Top-rated entry: {prompt_library.get("top_rated_title", "N/A")}

Showcase:
- Sessions held: {showcase_data.get("sessions", 0)}
- Total presentations: {showcase_data.get("presentations", 0)}
- Recording views: {showcase_data.get("recording_views", 0)}

Office hours:
- Sessions held: {office_hours_data.get("sessions", 0)}
- Questions answered: {office_hours_data.get("questions", 0)}
- Written summaries published: {office_hours_data.get("summaries", 0)}

Async channel:
- Tips of the Day posted: {channel_data.get("tips", 0)}
- Failure Friday posts: {channel_data.get("failure_friday", 0)}
- Mean reactions per post: {channel_data.get("mean_reactions", 0)}

Write a 2-paragraph assessment:
1. What the production data shows about the community's knowledge output this quarter
2. One specific gap and one specific strength, with a recommended action for each"""

    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=400,
        messages=[{"role": "user", "content": prompt}],
    )
    return resp.content[0].text


report = generate_knowledge_production_report(
    quarter="Q1 2025",
    prompt_library={"total_entries": 47, "new_this_quarter": 12, "archived": 3, "monthly_views_mean": 290, "top_rated_title": "Ticket handover summary"},
    showcase_data={"sessions": 3, "presentations": 9, "recording_views": 178},
    office_hours_data={"sessions": 12, "questions": 38, "summaries": 11},
    channel_data={"tips": 26, "failure_friday": 8, "mean_reactions": 6.2},
)
print(report)

def synthesise_cop_metrics_from_raw_data(
    quarter: str,
    slack_analytics: dict,
    lms_data: dict,
    usage_data: dict,
    survey_data: dict,
    membership_data: dict,
) -> dict:
    """Synthesise raw metrics from multiple sources into a structured CoP dashboard."""
    import json
    prompt = f"""Synthesise CoP health metrics from raw data sources.

Quarter: {quarter}

Slack channel analytics:
{json.dumps(slack_analytics, indent=2)}

LMS certification data:
{json.dumps(lms_data, indent=2)}

Claude usage analytics:
{json.dumps(usage_data, indent=2)}

Member survey data:
{json.dumps(survey_data, indent=2)}

Membership roster data:
{json.dumps(membership_data, indent=2)}

Compute and return JSON with:
- community_health: {{ active_rate_pct, attendance_rate_pct, nps, net_growth, rag_status }}
- knowledge_production: {{ library_entries, new_entries, monthly_views, tips_published, rag_status }}
- programme_impact: {{ governance_inputs, adoption_delta_pct, curriculum_changes, rag_status }}
- quality_signal: {{ out_of_scope_rate_pct, manager_confidence, incidents, rag_status }}
- overall_rag: "GREEN" | "AMBER" | "RED"
- one_sentence_summary: overall assessment

Where rag_status: GREEN if all targets met, AMBER if any below target, RED if critical threshold breached."""

    from anthropic import Anthropic
    client = Anthropic()
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=600,
        messages=[{"role": "user", "content": prompt}],
    )
    return json.loads(resp.content[0].text)


dashboard = synthesise_cop_metrics_from_raw_data(
    quarter="Q2 2025",
    slack_analytics={"channel_members": 134, "active_posters": 48, "tips_posted": 24, "reactions_per_post_avg": 5.8, "failure_friday_posts": 7},
    lms_data={"certifications_this_quarter": 29, "renewal_compliance_pct": 91, "advanced_certs": 6},
    usage_data={"cop_team_active_rate_pct": 67, "non_cop_team_active_rate_pct": 51, "out_of_scope_rate_pct": 6},
    survey_data={"member_nps": 35, "manager_confidence_mean": 3.8, "response_rate_pct": 68},
    membership_data={"total": 134, "new_this_quarter": 21, "departed": 4, "champions": 24, "champion_attrition": 2},
)
print(f"Overall: {dashboard.get('overall_rag')} — {dashboard.get('one_sentence_summary')}")
print(f"Community health: {dashboard['community_health']['rag_status']}")
print(f"Programme impact: {dashboard['programme_impact']['rag_status']}")

